import React from "react";
import { useDispatch, useSelector } from "react-redux";
import { FontAwesomeIcon } from "@fortawesome/react-fontawesome";
import { faCarrot, faTrash } from "@fortawesome/free-solid-svg-icons";
import { addPantryItem, removePantryItem } from "./pantrySlice";

const categories = ["protein", "produce", "grain", "dairy", "spice", "pantry", "other"];

const units = [
  { value: "", label: "No unit" },
  { value: "pcs", label: "pcs" },
  { value: "g", label: "grams (g)" },
  { value: "kg", label: "kilograms (kg)" },
  { value: "oz", label: "ounces (oz)" },
  { value: "lb", label: "pounds (lb)" },
  { value: "ml", label: "milliliters (ml)" },
  { value: "l", label: "liters (l)" },
  { value: "tsp", label: "teaspoons (tsp)" },
  { value: "tbsp", label: "tablespoons (tbsp)" },
  { value: "cup", label: "cups" },
  { value: "can", label: "cans" },
  { value: "pack", label: "packs" },
  { value: "bag", label: "bags" },
  { value: "bottle", label: "bottles" },
  { value: "clove", label: "cloves" },
  { value: "slice", label: "slices" },
];

export default function PantryPage() {
  const dispatch = useDispatch();
  const items = useSelector((state) => state.pantry.items);
  const [form, setForm] = React.useState({ name: "", category: "produce", quantity: "", unit: "" });

  function updateField(event) {
    setForm((current) => ({ ...current, [event.target.name]: event.target.value }));
  }

  function handleSubmit(event) {
    event.preventDefault();
    if (!form.name.trim()) return;
    dispatch(addPantryItem(form));
    setForm({ name: "", category: "produce", quantity: "", unit: "" });
  }

  return (
    <div className="page-stack">
      <div className="page-heading">
        <p className="eyebrow">Pantry manager</p>
        <h2>Ingredients on hand</h2>
        <p>Add the ingredients the AI chef can use when creating recipe suggestions.</p>
      </div>

      <form className="card form-grid" onSubmit={handleSubmit}>
        <label>
          Ingredient
          <input name="name" value={form.name} onChange={updateField} placeholder="e.g. lettuce" maxLength="40" />
        </label>
        <label>
          Category
          <select name="category" value={form.category} onChange={updateField}>
            {categories.map((category) => (
              <option key={category} value={category}>{category}</option>
            ))}
          </select>
        </label>
        <label>
          Quantity
          <input name="quantity" value={form.quantity} onChange={updateField} placeholder="2" />
        </label>
        <label>
          Unit
          <select name="unit" value={form.unit} onChange={updateField}>
            {units.map((unit) => (
              <option key={unit.value} value={unit.value}>{unit.label}</option>
            ))}
          </select>
        </label>
        <button className="primary-button" type="submit">
          <FontAwesomeIcon icon={faCarrot} /> Add item
        </button>
      </form>

      <div className="card list-card">
        {items.map((item) => (
          <div className="list-row" key={item.id}>
            <div>
              <strong>{item.name}</strong>
              <span>{item.category} {item.quantity && `• ${item.quantity} ${item.unit}`}</span>
            </div>
            <button className="icon-button danger" type="button" onClick={() => dispatch(removePantryItem(item.id))} aria-label={`Remove ${item.name}`}>
              <FontAwesomeIcon icon={faTrash} />
            </button>
          </div>
        ))}
      </div>
    </div>
  );
}
